	/**
	 * Fetch access token by exchanging the auth code received from oAuth login with broker
	 * @param {string} authCode - The auth code received from oAuth login with broker
	 * @returns {Promise<?string>} Access token if fetch successful or NULL otherwise
	 */
	const _getAccessTokenUsingAuthCode = async (authCode) => {
		if (!authCode || typeof authCode !== 'string' || authCode.toString().trim() === '') return null;
		try {
			// if (!authCode || typeof authCode !== 'string' || authCode.toString().trim() === '') throw new Error('Auth code not provided');
			/** @type {{s:1,at:'access_token'}|{s:0,m:'error message'}} */
			const access_token_resp = await invokeFn('kaagzi-lambda-upstox-getAccessToken', {
				c: authCode,
				s: 'wa', //wa -- WebApp, we -- WebExtension
			});
			if (!access_token_resp) throw new Error();
			if (!Object.prototype.hasOwnProperty.call(access_token_resp, 's')) throw new Error(); //here check response status
			if (access_token_resp.s === 0) throw new Error(access_token_resp.m); //Show error returned by backend
			if (access_token_resp.s !== 1) throw new Error(); //If still the status isn't okay

			if (!Object.prototype.hasOwnProperty.call(access_token_resp, 'at')) throw new Error();
			// console.log('Access token:', access_token_resp.at);
			return access_token_resp.at;
		} catch (err) {
			console.error(err.message || 'Error fetching access token from Upstox');
			// notify(err.message || 'Error fetching access token from Upstox', 'err');
			return null;
		}
	};

	/**
	 * Given the access-token, fetch user profile from the broker and update storage and state
	 * @param {string} upstoxAccessToken - The access token received from broker after exchanging authCode
	 * @returns {Promise<Boolean>} TRUE if profie fetched successfully, FALSE otherwise
	 */
	const _fetchUserProfileData_n_update_storage_n_state = async (upstoxAccessToken) => {
		try {
			const profileResponse = await fetch('https://api.upstox.com/v2/user/profile', {
				headers: {
					Authorization: 'Bearer ' + upstoxAccessToken,
					Accept: 'application/json',
				},
			}).catch((err) => {
				throw new Error('Error fetching profile data');
			});
			const profileData = await profileResponse.json();
			if (profileData.status !== 'success') throw new Error('Error fetching profile data');
			// console.log('Upstox user profile data:', profileData.data);

			//here save it in localstorage
			localStorage.setItem(
				'upstoxUser',
				JSON.stringify({
					atk: upstoxAccessToken,
					id: profileData.data.user_id,
					nm: profileData.data.user_name,
					eml: profileData.data.email,
					t: Date.now() / 1000, //login-time
				}),
			);
			//here update state
			setAccessToken(upstoxAccessToken);
			setId(profileData.data.user_id);
			setName(profileData.data.user_name);
			setEmail(profileData.data.email);
			return true;
		} catch (err) {
			return false;
		}
	};

