	/**
	 * Checks if user is stored in localstorage and updates state
	 * @returns {Promise<({atk:string,id:string,nm:string,eml:string,t:number}|false)>} Logged-in Upstox user-data or FALSE if no user is logged-in
	 */
	const chkStoredUpstoxUser_n_updateState = async () => {
		const storedUpstoxUserReadResultObj = localStorage.getItem('upstoxUser'); //await browser.storage.local.get('upstoxUser');
		if (!storedUpstoxUserReadResultObj) {
			// console.log('No logged-in Upstox user');
			_reset();
			return false;
		}

		const upstoxUserData = JSON.parse(storedUpstoxUserReadResultObj);
		//here check last-login timestamp (ie when the data was stored in storage) and check if it isn't before past 24 hrs (actually AngelOne says it's valid upto 28 hrs)
		if (Date.now() / 1000 - upstoxUserData.t > 86400) return false;
		//here maybe delete the user stored in localstorage

		//here update state
		setAccessToken(upstoxUserData.atk);
		setId(upstoxUserData.id);
		setName(upstoxUserData.nm);
		// console.log('upstoxUserData.nm:', upstoxUserData.nm);
		setEmail(upstoxUserData.eml);

		return upstoxUserData;
	};

	/** Logs user out of Upstox
	 * @returns {Promise<boolean>} TRUE upon successfully logging out
	 */
	const logOut = async () => {
		if (!accessToken) return false;
		try {
			const logoutResponse = await fetch('https://api.upstox.com/v2/logout', {
				method: 'DELETE',
				headers: {
					Authorization: 'Bearer ' + accessToken,
					Accept: 'application/json',
				},
				// body: '',
			}).catch((err) => {
				throw new Error();
			});
			const logoutResponseData = await logoutResponse.json();
			if (logoutResponseData.status !== 'success' || !logoutResponseData.data) throw new Error();
			_reset();
			//here clear localstorage
			// await browser.storage.local.remove('upstoxUser');
			localStorage.removeItem('upstoxUser');
			notify('Successfully logged out of Upstox');
			return true;
		} catch (err) {
			// console.error(err);
			notify('Error logging out of Upstox', 'err');
			return false;
		}
	};

	/**
	 * We listen for message containing aauth code from the oAuth popup
	 * @param {!{origin,data}} event - Storage Event
	 */
	const _handleMsgFromAuthPopup = (event) => {
		// if (event.origin !== 'http://localhost:8000') return;
		if (!event.source.location.href.startsWith('https://kaagzi.in/app/upstox/welcome')) return; //only entertain incoming messages from the popup

		// console.log('msg from popup', event);
		// console.log('msging window location', event.source.location.href);
		event.source.close(); //close the popup window	//we close() in the popup page too, but still do it here irrespectively
		authWindowRef.current = null;
		try {
			if (!Object.prototype.hasOwnProperty.call(event.data, 'authCode')) throw new Error();
			//here fetch access token
			(async () => {
				try {
					const upstoxAccessToken = await _getAccessTokenUsingAuthCode(event.data.authCode);
					if (!upstoxAccessToken) throw new Error('Error fetching access token from Upstox');
					const fetchProfileAndLogin = await _fetchUserProfileData_n_update_storage_n_state(upstoxAccessToken);
					if (!fetchProfileAndLogin) throw new Error('Error fetching user profile from Upstox');
					notify('Successfully logged into Upstox', 'success');
				} catch (err) {
					notify(err.message || 'Error while signing into Upstox', 'err');
				}
			})();
		} catch (err) {
			notify('Error while signing into Upstox', 'err');
		}
		// finally {
		// 	//here maybe clear any popup polling timer
		// }
	};

	/**
	 * We listen for any messages from the content-script
	 * @param {!{origin,data:{action,msgFlowDirection:'contentScript-to-webPage'}}} event - Post message Event
	 */
	const _handleMsgsFromContentScript = (event) => {
		if (event.source != window) return; // We only accept messages from ourselves, (ie sent by the same window object the content-script is running in)
		if (!event.origin.startsWith('http://localhost:') && event.origin !== 'https://kaagzi.in') {
			// console.warn('Does not accept incoming messages from ' + event.origin + ' origin');
			return;
		}
		//here also chk if message is from content-script to webpage and not the other way around
		if (!Object.prototype.hasOwnProperty.call(event.data, 'msgFlowDirection')) return;
		if (event.data.msgFlowDirection !== 'contentScript-to-webPage') return;

		if (!Object.prototype.hasOwnProperty.call(event.data, 'action')) return;
		switch (event.data.action) {
			case 'upstoxUserUpdated':
				//The content-script would have already written the updated data to the localstorage
				(async () => {
					await chkStoredUpstoxUser_n_updateState();
				})();
				break;
			// case 'userSignedOut':
			// 	signOut(true);
			// 	break;
			// default:
			// 	//do something default
			// 	console.log('User_ContextProvider received message from content-script with foll action: ' + event.data.action);
		}
	};

	useEffect(() => {
		window.addEventListener('message', _handleMsgFromAuthPopup);
		window.addEventListener('message', _handleMsgsFromContentScript);
		return () => {
			window.removeEventListener('message', _handleMsgFromAuthPopup);
			window.removeEventListener('message', _handleMsgsFromContentScript);
		};
	}, []); //runs only on mount

	useEffect(() => {
		(async () => {
			await chkStoredUpstoxUser_n_updateState();
		})();
	}, [isOnline]); //runs on mount and then whenever isOnline changes

	return (
		<>
			{id !== null && accessToken !== null ? (
				<UpstoxUserContext.Provider value={{ id, name, email, accessToken, chkIfUpstoxUserIsLoggedIn: chkStoredUpstoxUser_n_updateState, logOut }}>
					{children}
				</UpstoxUserContext.Provider>
			) : (
				// <div id={styles.noUserWrap}>
				// 	<Button onClick={launchWebAuthFlow_n_getToken}>Sign into Angel One</Button>
				// 	<LinkButton to={browser.runtime.getURL('app/appChooser/index.html')} variant="tertiary">
				// 		Choose different broker
				// 	</LinkButton>
				// </div>
				<BrokerLogin broker="Upstox" doOnLoginClick={openAuthWindow} referralUrlForNewSignupWithBroker="https://link.upstox.com/FxPt9MAeYxPsRSnS9" />
			)}
		</>
	);
