/** Active position data stored in 'positions' table with each position appended with instrument_token mapped from Upstox
 * @typedef {Object} UpstoxPosition
 * @property {?String} [id] - Trading Symbol suffixed with exchange (eg :NSE, :BSE) and further suffixed with direction (eg ':B' or ':S'). Sorting shall be by Trading Symbol
 * @property {String} sbl - Instrument name / Trading Symbol
 * @property {('NSE'|'BSE'|'NFO'|'CDS'|'MCX')} xh - Exchange
 * @property {Number} avg - Average entry price
 * @property {?Number} [sl] - Stop-loss price
 * @property {?Number} [tp] - Take-profit price
 * @property {Number} qty - Quantity
 * @property {?Number} [ltsz=1] - Lot Size
 * @property {Number} t - Timestamp in ms
 * @property {Number} [x] - Expiry timestamp in ms
 * @property {('B'|'S')} dir - Trade direction. 'B' for BUY trade | 'S' for SELL trade
 * @property {?number} instrument_token Instrument token mapped from Upstox Master Data
 */

/** @typedef {import('@types_appShared').Position} KaagziPosition Broker agnostic active-position data stored in 'positions' table */

//======================+
//		COMPONENT		|
//======================+

export default function UpstoxPositions() {
	const [isReady, setIsReady] = useState(false); //we shall set this to true once we receive the first quote tick from WS
	const [positionsAry, setPositionsAry] = useState(/** @type {UpstoxPosition[]} */ ([]));
	const [positionsNotFoundAry, setPositionsNotFoundAry] = useState(/** @type {{symbol:String,exchange:string}[]} */ ([]));
	const [totalPnL, setTotalPnL] = useState(0);
	const [currentlySelectedPos, setCurrentlySelectedPos] = useState(/** @type {UpstoxPosition} */ ({}));
	const [isWatchListViz, setIsWatchlistViz] = useState(false);

	const { notify } = useContext(ToastNotificationContext);
	const isOnline = useContext(NetworkCheckContext);
	const { checkIfPlanActive } = useContext(UserContext);
	// const { currentBroker } = useContext(StockMarketBrokerContext);
	const { name: brokerUserName, logOut: brokerLogOut } = useContext(UpstoxUserContext);
	const { quotes, tick, subscribeToQuotes, unsubscribeToQuotes } = useContext(UpstoxWebSocketContext);
	// const goToTab = useContext(TabsSwitcherContext);
	const { isMasterDataReady, getTokenForInstruments } = useContext(UpstoxMasterDataContext);
	const { getPosition, exitPosition, setPosition } = useContext(AppDataIndexedDbContext);
	// const appHeaderContainerElm = useContext(FullWidthAppRestrictedPageLayoutContext);

	// const { setBroker, setBrokerLoggedInUserName, setDoOnBrokerLogout, setDoOnWatchListBtnClick, isTradeHistoryViz, setIsTradeHistoryViz } = useContext(AppHeaderContext);

	// /** Gets array of tokens from array of position objects. ie. Reads tokens from each position object from positions state array into a new array
	//  * @returns {?number[]} Array of instrument tokens
	//  */
	// const _getArrayOfTokensFromArrayOfPositionObjs = () => {
	// 	if (positionsAry.length < 1) return null; //return [];
	// 	let tokensAry_notUnique = positionsAry.map((pos) => Number(pos.instrument_token));
	// 	return [...new Set(tokensAry_notUnique)]; //same as Array.from(new Set())	// removes duplicate entries that may hav got added in above operation
	// 	//// NOTE: We can use a SET instead of Array --> https://developer.mozilla.org/en-US/docs/Web/JavaScript/Reference/Global_Objects/Set
	// 	//// more info on above -->	https://developer.mozilla.org/en-US/docs/Web/JavaScript/Reference/Global_Objects/Set#remove_duplicate_elements_from_the_array
	// };

	const getPositions_n_loadIntoState_n_subscribeToWsLiveQuotes = async () => {
		try {
			const isPlanActive = await checkIfPlanActive(); //this shall cause the 'PlaneExpiryGateway' component to not render this component and display plan expired dialog
			if (!isPlanActive) throw new Error('Plan Expired!');
			//here we first read the generic broker-agnostic positions stored in Kaagzi DB
			const kaagziPositionsAry = await getPosition(null, null, null);
			if (!kaagziPositionsAry || !kaagziPositionsAry?.length) throw new Error('No positions found');

			//then resolve instrument_token (for use in WS live ticks) for each position by reading from Upstox Master-Data DB
			const mappedObj = kaagziPositionsAry.reduce((acc, item) => {
				// If the exchange key doesn't exist, init it with an empty array
				if (!acc[item.xh]) {
					acc[item.xh] = [];
				}
				// Push the current symbol onto the array for this exchange
				acc[item.xh].push(item.sbl);
				return acc;
			}, {});

			const tokenForInstrumentsObj = await getTokenForInstruments(mappedObj);
			if (!tokenForInstrumentsObj) throw new Error('Error inferring tokens for positions');
			if (!Object.prototype.hasOwnProperty.call(tokenForInstrumentsObj, 'instrumentsAndTheirToken'))
				throw new Error('Error inferring tokens for positions');
			/** @type {UpstoxPosition[]} */
			const upstoxPositionsAry = [];
			kaagziPositionsAry.forEach((position) => {
				position.instrument_token = tokenForInstrumentsObj.instrumentsAndTheirToken[`${position.sbl}:${position.xh}`] || null;
				upstoxPositionsAry.push(position); //now this position obj also has the instrument_token
			});
			if (kaagziPositionsAry.length < 1 && tokenForInstrumentsObj?.instrumentsNotFound?.length < 1) throw new Error('No positions found');

			if (tokenForInstrumentsObj?.instrumentsNotFound?.length > 0) {
				setPositionsNotFoundAry(tokenForInstrumentsObj.instrumentsNotFound);
				notify(tokenForInstrumentsObj.instrumentsNotFound.length + ' of the positions could not be loaded');
			}

			setPositionsAry(upstoxPositionsAry);
			//here subsribe to newly fetched positions
			// isOnline && (await subscribeToQuotes(upstoxPositionsAry.map(({ instrument_token }) => Number(instrument_token))));
			if (isOnline) {
				// const subscrptnResult =
				await subscribeToQuotes(upstoxPositionsAry.map(({ instrument_token }) => instrument_token));
				// await subscribeToQuotes(_segregateInstrumentTokenByExchanges(upstoxPositionsAry));
				// console.log('subscrptnResult:', subscrptnResult);
				await new Promise((resolve) => setTimeout(resolve, 1500)); //wait for 1.5 seconds for websocket to respond with the quotes
				setIsReady(true);
			}
		} catch (err) {
			// console.error(err);
			// notify(err?.message || 'Error reading positions', 'err');
			isOnline && positionsAry.length > 0 && unsubscribeToQuotes(positionsAry.map(({ instrument_token }) => instrument_token));
			// isOnline && positionsAry.length > 0 && unsubscribeToQuotes(_segregateInstrumentTokenByExchanges(positionsAry));
			setPositionsAry([]);
			return null;
		}
	};

	/** Opens new position or adds to already open position
	 * @param {string} tradingsymbol Instrument trading symbol
	 * @param {string} exchange Exchange
	 * @param {Number} ltp LTP
	 * @param {Number} qty Quantity
	 * @param {Number} [lotSize] Lot size
	 * @returns {Promise<?KaagziPosition>} broker agnostic position data written to DB or null
	 */
	const openNewOrAddToPosition = async (tradingsymbol, exchange, ltp, qty, lotSize) => {
		// console.log('Opeining pos for instrument ' + tradingsymbol);
		// console.table({ tradingsymbol, exchange, ltp, qty, lotSize });
		if (!tradingsymbol || typeof tradingsymbol !== 'string' || tradingsymbol.trim() === '') return null;
		if (!exchange || typeof exchange !== 'string' || exchange.trim() === '') return null;
		if (!ltp || isNaN(ltp)) return null;
		if (!qty || isNaN(qty) || !Number.isInteger(qty)) return null;

		try {
			const isPlanActive = await checkIfPlanActive(); //this shall cause the 'PlaneExpiryGateway' component to not render this component and display plan expired dialog
			if (!isPlanActive) throw new Error('Plan Expired!');
			/** @type {KaagziPosition} */
			const posData = {
				sbl: tradingsymbol,
				xh: exchange,
				avg: ltp,
				// sl: 0,
				// tp: 0,
				qty: Number(qty),
				t: Date.now(),
				// x: 'expiry datetime here',
				dir: 'B', //direction === 'B' ? 'B' : 'S',
			};
			if (lotSize && !isNaN(lotSize) && Number(lotSize) > 1) {
				posData.ltsz = Number(lotSize);
			}
			const writtenPos = await setPosition(posData);
			if (!writtenPos) throw new Error('Failed to open or update position'); //in case of max positions allowed, show appropriate message

			//here update the state in positions component or provider
			await getPositions_n_loadIntoState_n_subscribeToWsLiveQuotes(); //effectively refreshes positions to also display the newly-added / updated pos
			//note that the watchlist component unmounts after the position has been added and we may need to resubscribe to positions quotes after it has been closed, by watching for 'isWatchListViz' turning to false

			notify('Trade position ' + tradingsymbol + ' opened successfully', 'success');

			return writtenPos;
		} catch (err) {
			console.error(err);
			notify(err.message || 'Error opening or updating position', 'err');
			return null;
		}
	};

	/**
	 * Close position. Mostly used when either SL or TP is hit
	 * @param {UpstoxPosition} pos Upstox position object
	 * @param {number} exitPrice Exit price.Could either be the LTP in case of manually closing the pos. Else SL or TP
	 * @param {boolean} isSellTrade Whether it is a SELL trade
	 * @returns {Promise<boolean>}
	 */
	const _closePosition = async (pos, exitPrice, isSellTrade) => {
		try {
			const isPlanActive = await checkIfPlanActive(); //this shall cause the 'PlaneExpiryGateway' component to not render this component and display plan expired dialog
			if (!isPlanActive) throw new Error('Plan Expired!');
			const exitedPos = await exitPosition(pos.sbl, pos.xh, isSellTrade, exitPrice, pos.qty);
			if (!exitedPos) throw new Error('Failed to exit position');
			//here update the state in positions component or provider
			__updatePositionsAfterPosExit(exitedPos);
		} catch (err) {
			notify(err.message || 'Failed to close position', 'err');
			console.error(err);
		}
	};

	const __updatePositionsAfterPosExit = (exitedPos) => {
		const positionToUpdateOrRemove = positionsAry.find((pos) => pos.sbl === exitedPos.sbl && pos.xh === exitedPos.xh && pos.dir === exitedPos.dir);
		if (positionToUpdateOrRemove) {
			//here if exitedQty === purchasedQty, remove position from state
			if (positionToUpdateOrRemove.qty === exitedPos.qty) {
				//here unsubscribe from WS
				// isOnline && unsubscribeToQuotes(_segregateInstrumentTokenByExchanges([positionToUpdateOrRemove.instrument_token]));
				isOnline && unsubscribeToQuotes([positionToUpdateOrRemove.instrument_token]);
				setPositionsAry(positionsAry.filter((pos) => !(pos.sbl === exitedPos.sbl && pos.xh === exitedPos.xh && pos.dir === exitedPos.dir)));
			} else if (exitedPos.qty < positionToUpdateOrRemove.qty) {
				//else if only partial units exited, update pos with qty yet to be sold
				setPositionsAry(
					positionsAry.map((pos) => {
						if (pos.sbl === exitedPos.sbl && pos.xh === exitedPos.xh && pos.dir === exitedPos.dir) {
							pos.qty = pos.qty - exitedPos.qty;
						}
						return pos;
					}),
				);
			}
		}
	};
	// useEffect(() => {
	// 	setBroker('Angel One');
	// 	setBrokerLoggedInUserName(brokerUserName);
	// 	setDoOnBrokerLogout(brokerLogOut);
	// 	setDoOnWatchListBtnClick(() => {
	// 		setIsWatchlistViz(true);
	// 	});
	// }, []);
	// useEffect(() => {
	// 	// getPositions_n_loadIntoState_n_subscribeToWsLiveQuotes();
	// 	(async () => {
	// 		await getPositions_n_loadIntoState_n_subscribeToWsLiveQuotes();
	// 	})();
	// 	return () => {
	// 		isOnline && positionsAry.length > 0 && unsubscribeToQuotes(positionsAry.map(({ instrument_token }) => Number(instrument_token)));
	// 	};
	// }, []);
	let hasAlreadyRunOnMount = false;
	useEffect(() => {
		if (isMasterDataReady) {
			if (hasAlreadyRunOnMount) {
				//if this is a subsequent run and not the first mount run
				(async () => {
					await checkIfPlanActive(); //this shall cause the 'PlaneExpiryGateway' component to not render this component and display plan expired dialog

					if (isOnline && positionsAry.length > 0) {
						await new Promise((resolve) => setTimeout(resolve, 2000)); //wait for 2 seconds for websocket connection to be established successfully
						// await subscribeToQuotes(_segregateInstrumentTokenByExchanges(positionsAry));
						await subscribeToQuotes(positionsAry.map(({ instrument_token }) => instrument_token));
					}
					//foll call shall anyhow fail coz no network wud b available
					// else {
					// 	unsubscribeToQuotes(positionsAry.map(({ instrument_token }) => Number(instrument_token)));
					// }
				})();
			} else {
				//if this is first mount run
				(async () => {
					await getPositions_n_loadIntoState_n_subscribeToWsLiveQuotes();
					setIsReady(true);
				})();

				hasAlreadyRunOnMount = true;
			}
		}
		return () => {
			// isOnline && positionsAry.length > 0 && unsubscribeToQuotes(_segregateInstrumentTokenByExchanges(positionsAry));
			isOnline && positionsAry.length > 0 && unsubscribeToQuotes(positionsAry.map(({ instrument_token }) => instrument_token));
		};
	}, [isOnline, isMasterDataReady]); //runs on mount & when 'isOnline' or 'isMasterData' changes

	// useEffect(() => {
	// 	if (positionsAry.length < 1) return;
	// 	//here read position tokens into array
	// 	const posTokensAry = _getArrayOfTokensFromArrayOfPositionObjs();
	// 	//note that it may be the case that 'posTokensAry' now holds one less token after order getting closed and in such case we also need to unsubscribe that token.
	// 	//we do so once we receive order-close confirmation message from the bg
	// 	//here subscribe to WS
	// 	(async () => {
	// 		await subscribeToQuotes(posTokensAry);
	// 	})();

	// 	return () => {
	// 		//here read position tokens into array
	// 		const posTokensAry = _getArrayOfTokensFromArrayOfPositionObjs();
	// 		//here unsubscribe to WS
	// 		unsubscribeToQuotes(posTokensAry);
	// 	};
	// }, [positionsAry]); //run on first mount and then whenever positionsAry state changes

	useEffect(() => {
		if (Object.keys(quotes).length < 1) return;

		// setIsReady(true); //on receiving first tick quote from WS, we hide loading overlay by setting this to true (and also sets on subsequent runs but doesnt matter)

		//here calculate total PnL
		let totalPnL = 0;
		// console.log('quotes', quotes);
		positionsAry.forEach((pos) => {
			if (!Object.prototype.hasOwnProperty.call(quotes, pos.instrument_token)) return;
			const currentPrice = quotes[pos.instrument_token].ltp;

			// const individualPositionPnL = (currentPrice - pos.avg) * pos.qty;
			// totalPnL += individualPositionPnL;
			// totalPnL += (quotes[pos.instrument_token].ltp - pos.avg) * pos.qty;

			//here check for SL or TP
			if (pos.dir === 'B') {
				//if it's a BUY trade
				totalPnL += (currentPrice - pos.avg) * pos.qty;

				if (pos.sl !== null && pos.sl !== undefined) {
					if (currentPrice <= pos.sl) {
						_closePosition(pos, pos.sl, false);
						notify(`SL hit for ${pos.xh}:${pos.sbl} buy trade`, 'alert');
					}
				}
				if (pos.tp !== null && pos.tp !== undefined) {
					if (currentPrice >= pos.tp) {
						_closePosition(pos, pos.tp, false);
						notify(`TP hit for ${pos.xh}:${pos.sbl} buy trade`, 'success');
					}
				}
			} else {
				//if it's a SELL trade
				totalPnL += (pos.avg - currentPrice) * pos.qty;

				if (pos.sl !== null && pos.sl !== undefined) {
					if (currentPrice >= pos.sl) {
						_closePosition(pos, pos.sl, true);
						notify(`SL hit for ${pos.xh}:${pos.sbl} sell trade`, 'alert');
					}
				}
				if (pos.tp !== null && pos.tp !== undefined) {
					if (currentPrice <= pos.tp) {
						_closePosition(pos, pos.tp, true);
						notify(`TP hit for ${pos.xh}:${pos.sbl} sell trade`, 'success');
					}
				}
			}
		});
		setTotalPnL(totalPnL);
		// }, [quotes, positionsAry]); //runs on first mount and then whenever quotes or positionsAry changes
	}, [tick, positionsAry]); //runs on first mount and then whenever 'tick' or positionsAry changes

	return (
		<>
			{/* {appHeaderContainerElm &&
				createPortal(
					<AppHeader
						broker="Angel One"
						brokerLoggedInUserName={brokerUserName}
						brokerLogOut={brokerLogOut}
						doOnWatchListBtnClick={() => {
							setIsWatchlistViz(true);
						}}
					/>,
					appHeaderContainerElm,
				)} */}
			<AppHeader
				broker="Upstox"
				brokerLoggedInUserName={brokerUserName}
				brokerLogOut={brokerLogOut}
				doOnWatchListBtnClick={() => {
					setIsWatchlistViz(true);
				}}
			/>
			<main>
				<div className={styles.positionsC}>
					{!isReady ? (
						<>
							{/* <div className={styles.noPosEmptyC}>Reading Positions</div> */}
							<div className={styles.noPosEmptyC} />
							{isMasterDataReady && <Loading note="Loading Positions" />}
						</>
					) : positionsAry.length < 1 ? (
						// <div className={styles.noPosEmptyC}>No open positions. Add new</div>
						<EmptyGfx
							icon="briefcase"
							note="No Open Positions"
							ctaFn={() => {
								// goToTab(0); //switches over to marketwatch tab
								// notify('Enter new position for any of the instruments from watchlist');
								setIsWatchlistViz(true);
							}}
							ctaBtnText="Open New Position"
						/>
					) : (
						<>
							<div className={styles.positionsListC}>
								{positionsAry.map((pos, i) => {
									//here check if position is expired
									const { sbl, xh, avg, qty, dir, x, instrument_token } = pos;

									//here check if instrument_token has been mapped from Kite Master Data
									// if(!instrument_token)return <li>mark as expired</li>

									// //here calculate pnl
									// const lastTradedPrice = quotes[instrument_token].ltp;
									// const posPnl = (dir === 'S' ? avg - lastTradedPrice : lastTradedPrice - avg) * qty;

									// return (
									// 	<li key={`${i}:${instrument_token}`} className={dir === 'S' ? styles.isSell : styles.isBuy}>
									// 		{/* we cannot have token alone as the key since it may be used twice (ie in case opp direction trade exists) */}
									// 		<div className={styles.dataRow}>
									// 			<span>{sbl}</span>
									// 			{/* <span className="isGreen amtGreen">3,390.0</span> */}
									// 			<ColoredNumberDisplay currentVal={posPnl} baseVal={0} />
									// 		</div>
									// 		<div className={styles.metaDataRow}>
									// 			<span className={styles.qty}>{qty}</span>
									// 			<span className={styles.avg}>{avg}</span>
									// 			<span className={styles.ltp}>
									// 				<PreventRerenderIfValueInvalid value={lastTradedPrice} />
									// 			</span>
									// 			{/* Use memo for above value wherein we prevent rerender if value is null, thus displaying previous tick value instead of null*/}
									// 		</div>
									// 	</li>
									// );
									return (
										<PositionListItem
											wrapperElement="div"
											key={`${i}:${instrument_token}`}
											tradingsymbol={sbl}
											exchange={xh}
											qty={qty}
											avg={avg}
											// ltp={Object.prototype.hasOwnProperty.call(quotes, instrument_token) ? quotes[instrument_token].ltp : null}
											ltp={quotes?.[instrument_token]?.ltp}
											// ltp={quotes[instrument_token].ltp}
											direction={dir}
											onClick={(e) => {
												setCurrentlySelectedPos(pos);
												e.stopPropagation();
											}}
										/>
									);
								})}
								{positionsNotFoundAry.length > 0 && (
									<div className={styles.positionsNotFoundC}>
										<h3>Positions not found</h3>
										<p>Foll instruments not found in Upstox</p>
										{positionsNotFoundAry.map(({ symbol, exchange }) => (
											<div key={`${symbol}:${exchange}`}>
												<span>{symbol}</span>
												<span>{exchange}</span>
												{/* <Button
											variant="tertiary"
											isDark={true}
											icon="trash-2"
											onClick={(e) => {
												removeNotFoundInstrument(symbol, exchange);
												// e.stopPropagation(); //prevents event on parent elm rom firing
											}}
										/> */}
											</div>
										))}
									</div>
								)}
							</div>
							<div className={styles.positionsFtr}>
								<Button
									variant="primary"
									onClick={() => {
										// goToTab(0); //switches over to marketwatch tab
										// notify('On click we show watchlist inside bottom-sheet');
										setIsWatchlistViz(true);
										// notify('Enter new position for any of the instruments from watchlist');
									}}
								>
									New Position
								</Button>
								<span className={styles.totalPnL}>
									{/* Total: <span className="isGreen amtGreen">2,651.10</span> */}
									Total: <ColoredNumberDisplay currentVal={totalPnL} baseVal={0} />
								</span>
							</div>
						</>
					)}

					{Object.keys(currentlySelectedPos).length > 0 && (
						<BottomSheet
							doOnClose={() => {
								setCurrentlySelectedPos({});
							}}
						>
							{/* <ExitTradePositionDialog
							tradingsymbol={currentlySelectedPos.sbl}
							exchange={currentlySelectedPos.xh}
							purchasdQty={currentlySelectedPos.qty}
							lotSize={Object.prototype.hasOwnProperty.call(currentlySelectedPos, 'ltsz') ? currentlySelectedPos.ltsz : 1}
							avgEntryPrice={currentlySelectedPos.avg}
							ltp={quotes?.[currentlySelectedPos.instrument_token]?.ltp}
							direction={currentlySelectedPos.dir}
							doOnSuccessfulExit={(exitedPos) => {
								//here if exitedQty is === to purchasedQty, remove position from state
								//else if only partial units exited, update pos with qty yet to be sold
								console.log('doOnSuccessfulExit() callback --> exitedPos:', exitedPos);
							}}
						/> */}
							{(close) => (
								<ExitTradePositionDialog
									tradingsymbol={currentlySelectedPos.sbl}
									exchange={currentlySelectedPos.xh}
									purchasdQty={currentlySelectedPos.qty}
									lotSize={Object.prototype.hasOwnProperty.call(currentlySelectedPos, 'ltsz') ? currentlySelectedPos.ltsz : 1}
									avgEntryPrice={currentlySelectedPos.avg}
									// ltp={quotes?.[currentlySelectedPos.instrument_token]?.ltp}
									ltp={quotes?.[currentlySelectedPos.instrument_token]?.ltp}
									direction={currentlySelectedPos.dir}
									// doOnSuccessfulExit={(exitedPos) => {
									// 	__updatePositionsAfterPosExit(exitedPos);
									// 	console.log('doOnSuccessfulExit() callback --> exitedPos:', exitedPos);
									// }}
									doOnSuccessfulExit={__updatePositionsAfterPosExit}
									closeDialog={close}
								/>
							)}
						</BottomSheet>
					)}
				</div>
			</main>

			{isWatchListViz && (
				<BottomSheet
					doOnClose={() => {
						setIsWatchlistViz(false);
					}}
					title="Watchist"
				>
					{/* {(close) => <p>Test</p>} */}

					{(close, setSheetTitle, setSheetDesc) => (
						<UpstoxMarketWatch
							openNewOrAddToPosition={openNewOrAddToPosition}
							setBottomSheetTitle={setSheetTitle}
							setBottomSheetDesc={setSheetDesc}
							closeBottomSheet={close}
						/>
					)}
				</BottomSheet>
			)}
			{/* {isTradeHistoryViz && (
				<BottomSheet
					title="Trade History"
					doOnClose={() => {
						setIsTradeHistoryViz(false);
					}}
				>
					<TradeHistory />
				</BottomSheet>
			)} */}
		</>
	);
}
